import{_ as o,b as r,e as a,al as n}from"./chunks/framework.aXkQZaJg.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"cd437382d5be1b6fdadbf4dbe507c2a9bacaeb41"};var e=new t.Error().stack;e&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[e]="8e168d1b-f4da-480f-a18b-25c0099ffb2a",t._sentryDebugIdIdentifier="sentry-dbid-8e168d1b-f4da-480f-a18b-25c0099ffb2a")}catch{}})();const g=JSON.parse('{"title":"什么是 DOM？","description":"","frontmatter":{},"headers":[],"relativePath":"html/basic/domAttributes.md","filePath":"html/basic/domAttributes.md","lastUpdated":1782271806000}'),c={name:"html/basic/domAttributes.md"};function l(t,e,d,s,i,h){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="什么是-dom" tabindex="-1">什么是 DOM？ <a class="header-anchor" href="#什么是-dom" aria-label="Permalink to &quot;什么是 DOM？&quot;">​</a></h1><p>文档对象模型（DOM）是 HTML 和 XML 文档的编程接口。 它将文档解析为一个由节点和对象（包含属性和方法）组成的结构，通常是一个树状结构。 简单来说，DOM 就像一座桥梁，连接了网页和脚本语言（主要是 JavaScript），让我们可以通过编程来改变文档的结构、样式和内容。</p><h2 id="_1-dom-api-概览" tabindex="-1">1. DOM API 概览 <a class="header-anchor" href="#_1-dom-api-概览" aria-label="Permalink to &quot;1. DOM API 概览&quot;">​</a></h2><p>DOM API 是由一系列的接口（方法和属性）组成的，它允许我们对 HTML 元素进行增删改查等操作。 这是一个由 W3C 和 WHATWG 共同制定的标准，并被现代浏览器广泛支持。</p><p>以下是一些最核心和常用的 DOM API：</p><h3 id="_1-1-节点选择-获取元素" tabindex="-1">1.1 节点选择（获取元素） <a class="header-anchor" href="#_1-1-节点选择-获取元素" aria-label="Permalink to &quot;1.1 节点选择（获取元素）&quot;">​</a></h3><p>要操作一个元素，首先需要获取它。DOM 提供了多种选择元素的方法：</p><table tabindex="0"><thead><tr><th>方法</th><th>描述</th></tr></thead><tbody><tr><td><code>getElementById(id)</code></td><td>通过元素的 <code>id</code> 属性获取一个元素节点。</td></tr><tr><td><code>getElementsByTagName(tagName)</code></td><td>通过标签名获取一个元素节点列表 (HTMLCollection)。</td></tr><tr><td><code>getElementsByClassName(className)</code></td><td>通过类名获取一个元素节点列表 (HTMLCollection)。</td></tr><tr><td><code>querySelector(selector)</code></td><td>通过 CSS 选择器获取匹配的第一个元素节点。</td></tr><tr><td><code>querySelectorAll(selector)</code></td><td>通过 CSS 选择器获取匹配的所有元素节点列表 (NodeList)。</td></tr></tbody></table><h3 id="_1-2-节点操作" tabindex="-1">1.2 节点操作 <a class="header-anchor" href="#_1-2-节点操作" aria-label="Permalink to &quot;1.2 节点操作&quot;">​</a></h3><p>获取到元素节点后，我们就可以对它们进行各种操作了。</p><p><strong>1. 创建和添加节点</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>描述</th></tr></thead><tbody><tr><td><code>createElement(tagName)</code></td><td>创建一个新的元素节点。</td></tr><tr><td><code>createTextNode(text)</code></td><td>创建一个新的文本节点。</td></tr><tr><td><code>appendChild(node)</code></td><td>将一个节点添加到指定父节点的子节点列表末尾。</td></tr><tr><td><code>insertBefore(newNode, referenceNode)</code></td><td>在指定的已有子节点之前插入一个新节点。</td></tr></tbody></table><p><strong>2. 删除和替换节点</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>描述</th></tr></thead><tbody><tr><td><code>removeChild(child)</code></td><td>删除一个子节点。</td></tr><tr><td><code>replaceChild(newChild, oldChild)</code></td><td>替换一个子节点。</td></tr></tbody></table><p><strong>3. 修改节点内容</strong></p><table tabindex="0"><thead><tr><th>属性</th><th>描述</th></tr></thead><tbody><tr><td><code>innerHTML</code></td><td>获取或设置一个元素内部的 HTML 内容。</td></tr><tr><td><code>textContent</code></td><td>获取或设置一个元素及其所有后代的文本内容。</td></tr></tbody></table><p><strong>4. 修改节点属性</strong></p><table tabindex="0"><thead><tr><th>方法/属性</th><th>描述</th></tr></thead><tbody><tr><td><code>getAttribute(attributeName)</code></td><td>获取指定属性的值。</td></tr><tr><td><code>setAttribute(attributeName, value)</code></td><td>设置指定属性的值。</td></tr><tr><td><code>removeAttribute(attributeName)</code></td><td>移除指定的属性。</td></tr><tr><td><code>dataset</code></td><td>访问元素的 <code>data-*</code> 自定义属性。</td></tr></tbody></table><p><strong>5. 修改节点样式</strong></p><table tabindex="0"><thead><tr><th>属性</th><th>描述</th></tr></thead><tbody><tr><td><code>style</code></td><td>通过 <code>style</code> 属性可以直接读写元素的内联样式，例如 <code>element.style.color = &#39;red&#39;</code>。</td></tr><tr><td><code>classList</code></td><td>通过 <code>classList.add()</code>, <code>classList.remove()</code>, <code>classList.toggle()</code> 等方法来操作元素的类名，这也是推荐的修改样式的方式。</td></tr></tbody></table><h2 id="_2-常见问题-faq" tabindex="-1">2. 常见问题 (FAQ) <a class="header-anchor" href="#_2-常见问题-faq" aria-label="Permalink to &quot;2. 常见问题 (FAQ)&quot;">​</a></h2><h3 id="_2-1-innerhtml-vs-textcontent-vs-innertext" tabindex="-1"><strong>2.1 <code>innerHTML</code> vs <code>textContent</code> vs <code>innerText</code></strong> <a class="header-anchor" href="#_2-1-innerhtml-vs-textcontent-vs-innertext" aria-label="Permalink to &quot;**2.1 `innerHTML` vs `textContent` vs `innerText`**&quot;">​</a></h3><ul><li><strong><code>innerHTML</code></strong>: 会解析并渲染 HTML 标签。如果你插入的内容来自用户，可能会有 XSS 攻击的风险。</li><li><strong><code>textContent</code></strong>: 不会解析 HTML 标签，会原样输出。它会获取所有子元素，包括 <code>&lt;script&gt;</code> 和 <code>&lt;style&gt;</code> 元素的内容。</li><li><strong><code>innerText</code></strong>: 同样不解析 HTML，但它会考虑 CSS 样式，不会返回被隐藏的文本（例如 <code>display: none;</code> 的元素），并且会触发布局重排（reflow），性能上不如 <code>textContent</code>。</li></ul><h3 id="_2-2-children-vs-childnodes" tabindex="-1"><strong>2.2 <code>children</code> vs <code>childNodes</code></strong> <a class="header-anchor" href="#_2-2-children-vs-childnodes" aria-label="Permalink to &quot;**2.2 `children` vs `childNodes`**&quot;">​</a></h3><ul><li><strong><code>children</code></strong>: 只返回元素的<strong>元素子节点</strong>（HTML 元素），是一个 <code>HTMLCollection</code>。</li><li><strong><code>childNodes</code></strong>: 返回所有类型的<strong>子节点</strong>，包括元素节点、文本节点（比如换行符和空格）、注释节点等，是一个 <code>NodeList</code>。</li></ul><p>在大多数情况下，如果你只想操作子元素，<code>children</code> 会是更方便和安全的选择。</p><h3 id="_2-3-htmlcollection-vs-nodelist" tabindex="-1"><strong>2.3 <code>HTMLCollection</code> vs <code>NodeList</code></strong> <a class="header-anchor" href="#_2-3-htmlcollection-vs-nodelist" aria-label="Permalink to &quot;**2.3 `HTMLCollection` vs `NodeList`**&quot;">​</a></h3><ul><li><strong><code>HTMLCollection</code></strong>: 是一个<strong>动态</strong>的集合。当文档中的元素发生变化时，<code>HTMLCollection</code> 会自动更新。例如 <code>getElementsByTagName</code> 返回的就是 <code>HTMLCollection</code>。</li><li><strong><code>NodeList</code></strong>: 通常是一个<strong>静态</strong>的集合，但也可能是动态的（取决于获取它的方法）。例如 <code>querySelectorAll</code> 返回的是静态的 <code>NodeList</code>，而 <code>childNodes</code> 返回的是动态的。</li></ul><p>对动态集合进行循环操作时要特别小心，因为在循环中修改 DOM 可能会导致死循环。</p><h3 id="_2-4-dom-操作的性能问题" tabindex="-1"><strong>2.4 DOM 操作的性能问题</strong> <a class="header-anchor" href="#_2-4-dom-操作的性能问题" aria-label="Permalink to &quot;**2.4 DOM 操作的性能问题**&quot;">​</a></h3><p>频繁地、大量地直接操作 DOM 可能会导致页面性能下降，因为每次 DOM 的改变都可能触发浏览器的重绘（repaint）和重排（reflow）。</p><p><strong>解决方案：</strong></p><ul><li><strong>减少 DOM 访问</strong>：将 DOM 元素的引用缓存到变量中，避免在循环中反复查询。</li><li><strong>批量更新</strong>：使用 <code>DocumentFragment</code> 作为临时容器，在内存中构建好 DOM 子树，然后一次性地添加到主 DOM 中。</li><li><strong>使用现代框架</strong>：像 React、Vue 等现代 JavaScript 框架使用虚拟 DOM（Virtual DOM）来最小化和批量化对真实 DOM 的操作，从而提高性能。</li></ul><h3 id="_2-5-跨浏览器兼容性" tabindex="-1"><strong>2.5 跨浏览器兼容性</strong> <a class="header-anchor" href="#_2-5-跨浏览器兼容性" aria-label="Permalink to &quot;**2.5 跨浏览器兼容性**&quot;">​</a></h3><p>虽然现在主流浏览器的 DOM API 实现已经非常标准化，但在一些旧的浏览器或者处理某些边缘情况时，仍然可能存在细微的差异。</p><p><strong>解决方案：</strong></p><ul><li><strong>使用成熟的库</strong>：像 jQuery 这样的库在早期很好地解决了跨浏览器兼容性问题。</li><li><strong>查阅文档</strong>：在开发时，可以查阅 MDN 等网站，了解 API 的浏览器兼容性情况。</li><li><strong>功能检测</strong>：在使用某个 API 之前，先检查它是否存在。</li></ul>',37)])])}const u=o(c,[["render",l]]);export{g as __pageData,u as default};
